def get_partner_webhook_config(secret_name: str, region_name: str | None = None) -> dict:
    if boto3 is None:
        raise RuntimeError("boto3 is required to load configuration from AWS Secrets Manager")

    client = boto3.client("secretsmanager", region_name=region_name)
    response = client.get_secret_value(SecretId=secret_name)

    secret_string = response.get("SecretString")
    if not secret_string:
        raise RuntimeError(f"Secret {secret_name} does not contain SecretString")

    import json

    return json.loads(secret_string)